import jwt

def decode_and_verify_jwt(token, secret_key, algorithm='HS256'):
    try:
        # Decode the token without verification
        decoded_token = jwt.decode(token, options={"verify_signature": False})
        
        # Verify the token with the provided secret key and algorithm
        verified_token = jwt.decode(token, secret_key, algorithms=[algorithm])
        
        return {
            "decoded": decoded_token,
            "verified": verified_token
        }
    except jwt.ExpiredSignatureError:
        return {"error": "Token has expired"}
    except jwt.InvalidTokenError as e:
        return {"error": f"Invalid token: {str(e)}"}

